class Solution:
  def numComponents(self, adj) -> int:
    visited = set()
    res = 0
    for node in adj.keys():
      if node not in visited:
        res += 1
        stack = [node]
        while stack:
          curr_node = stack.pop()
          visited.add(curr_node)
          for neighbor in adj[curr_node]:
            if neighbor not in visited:
              stack.append(neighbor)
    return res

