    tokens = self.readLine().split()
    return int(tokens[0])

  def readList(self):
    tokens = self.readLine().split()
    return [int(t) for t in tokens]

class SolutionRunner:
  def __init__(self):
    self.inputReader = InputReader()

  def run(self):
    n = self.inputReader.readInt()
    adj = {}
    for i in range(n):
      tokens = self.inputReader.readLine().split()
      node = int(tokens[0])
      adj[node] = [int(t) for t in tokens[1:] if int(t) != node]
    sol = Solution()
    print(sol.numComponents(adj))

if __name__ == '__main__':
  SolutionRunner().run()

