// Solution.cpp
#include <iostream>
#include <vector>
using namespace std;

class InputReader {
public:
  InputReader() {}

  int readInt() {
    int res;
    cin >> res;
    return res;
  }

  vector<int> readList() {
    vector<int> res;
    for (int i = 0; i < 3; ++i) {
      res.push_back(readInt());
    }
    return res;
  }
};


class Solution {
public:
  int numComponents(vector<vector<int>>& adj) {
    unordered_set<int> visited;
    int res = 0;
    for (auto node : adj[0]) {
      if (!visited.count(node)) {
        res += dfs(node, visited);
      }
    }
    return res;

    int dfs(int node, unordered_set<int>& visited) {
      visited.insert(node);
      for (int neighbor : adj[node]) {
        if (!visited.count(neighbor)) {
          return dfs(neighbor, visited) + 1;
        }
      }
      return 1;
    }
  }
};

